const d = $input.first().json;
const yaml = d.yaml_proposed || '';
const preview = yaml.length > 800 ? yaml.substring(0, 800) + '\n...(tronqué)' : yaml;
return [{
  json: {
    ...d,
    yaml_preview: preview,
    subject: `[Middleware Ramery] Nouveau fournisseur à valider : ${d.supplier_guess}`,
    body_html: `<html><body style="font-family:sans-serif;max-width:700px;margin:0 auto">
<h2 style="color:#1a7f5a">Nouveau fournisseur détecté</h2>
<table style="width:100%;border-collapse:collapse">
<tr><td style="padding:6px;font-weight:bold">Fichier :</td><td>${d.filename}</td></tr>
<tr><td style="padding:6px;font-weight:bold">Dossier SharePoint :</td><td>${d.folder_name}</td></tr>
<tr><td style="padding:6px;font-weight:bold">Fournisseur suggéré :</td><td><strong>${d.supplier_guess}</strong></td></tr>
</table>
<h3>YAML proposé par l'IA</h3>
<pre style="background:#f5f5f5;padding:16px;border-radius:4px;font-size:13px;overflow:auto">${preview}</pre>
<p>Veuillez valider ou rejeter cette configuration :</p>
<p>
<a href="${d.approve_url}" style="background:#1a7f5a;color:white;padding:12px 24px;border-radius:4px;text-decoration:none;margin-right:16px">✓ Approuver</a>
<a href="${d.reject_url}" style="background:#c0392b;color:white;padding:12px 24px;border-radius:4px;text-decoration:none">✗ Rejeter</a>
</p>
<p style="color:#888;font-size:12px">ID : ${d.pending_id}</p>
</body></html>`
  }
}];
